#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int** tshirts = (int**)malloc(N * sizeof(int*));
        int* counts = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            tshirts[i] = (int*)malloc(100 * sizeof(int));
            int count = 0;
            for (int j = 0; j < 100; j++) {
                tshirts[i][j] = 0;
            }
            int temp;
            while (scanf("%d", &temp) == 1) {
                tshirts[i][temp - 1] = 1;
                count++;
                if (getchar() == '\n') break;
            }
            counts[i] = count;
        }
        long long result = 1;
        int available = 100;
        for (int i = 0; i < N; i++) {
            long long temp = factorial(available);
            for (int j = 0; j < counts[i]; j++) {
                temp = (temp * (available - j)) % MOD;
            }
            result = (result * temp) % MOD;
            available -= counts[i];
        }
        printf("%lld\n", result);
        for (int i = 0; i < N; i++) {
            free(tshirts[i]);
        }
        free(tshirts);
        free(counts);
    }
    return 0;
}

